
.ellia-beauty-shell {
  position: relative;
  display: flex;
  gap: 2rem;
  width: 100%;
  min-height: 500px;
  padding: 3rem 2.5rem 2rem;
  border: 1px solid rgba(155, 89, 182, 0.2);
  border-radius: 4px;
  background: rgba(15, 8, 22, 0.85);
  box-shadow:
    0 30px 60px rgba(0, 0, 0, 0.9),
    inset 0 0 60px rgba(202, 164, 93, 0.03);
  backdrop-filter: blur(12px);
  overflow: hidden;
}

.ellia-beauty-shell.is-intro {
  box-shadow:
    0 30px 60px rgba(0, 0, 0, 0.9),
    inset 0 0 60px rgba(202, 164, 93, 0.05);
}

.ellia-beauty-inner-frame {
  position: absolute;
  inset: 14px;
  z-index: 10;
  border: 1px solid rgba(202, 164, 93, 0.25);
  pointer-events: none;
}

.ellia-beauty-frame-dot {
  position: absolute;
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: #caa45d;
  box-shadow:
    0 0 8px #caa45d,
    0 0 15px rgba(202, 164, 93, 0.6);
}

.dot-tl {
  top: -2.5px;
  left: -2.5px;
}

.dot-tr {
  top: -2.5px;
  right: -2.5px;
}

.dot-bl {
  bottom: -2.5px;
  left: -2.5px;
}

.dot-br {
  right: -2.5px;
  bottom: -2.5px;
}

.ellia-beauty-nav-btn {
  position: absolute;
  top: 1.2rem;
  z-index: 20;
  display: flex;
  align-items: center;
  border: none;
  background: transparent;
  color: rgba(224, 176, 255, 0.5);
  font-family: 'Noto Serif SC', serif;
  font-size: 0.8rem;
  letter-spacing: 0.1em;
  cursor: pointer;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.ellia-beauty-nav-btn:hover {
  color: #caa45d;
  text-shadow: 0 0 8px rgba(202, 164, 93, 0.6);
}

.ellia-beauty-nav-btn-left {
  left: 2.5rem;
}

.ellia-beauty-nav-btn-right {
  right: 2.5rem;
}

.ellia-beauty-nav-btn-left:hover {
  transform: translateX(-4px);
}

.ellia-beauty-nav-btn-right:hover {
  transform: translateX(4px);
}

.ellia-beauty-pane-left {
  position: relative;
  z-index: 5;
  display: flex;
  flex: 1.1;
  flex-direction: column;
  gap: 1.2rem;
  margin-top: 1rem;
  padding-right: 2rem;
}

.ellia-beauty-pane-left::after {
  content: '';
  position: absolute;
  top: 2%;
  right: -1rem;
  bottom: 2%;
  width: 1px;
  background: linear-gradient(to bottom, transparent, rgba(224, 176, 255, 0.25), transparent);
}

.ellia-beauty-pane-right {
  position: relative;
  z-index: 5;
  display: flex;
  flex: 0.9;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  margin-top: 1rem;
  padding-left: 1rem;
}

.ellia-beauty-greeting {
  margin-bottom: 0.5rem;
  color: #e0b0ff;
  font-size: 0.85rem;
  line-height: 1.6;
  text-align: justify;
  text-shadow: 0 0 8px rgba(0, 0, 0, 0.8);
}

.ellia-beauty-settings-group {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.ellia-beauty-face-group {
  margin-top: 0.5rem;
}

.ellia-beauty-settings-title {
  color: rgba(202, 164, 93, 0.7);
  font-size: 0.75rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}

.ellia-beauty-settings-title.title-curious {
  color: #e0b0ff;
  letter-spacing: 0.1em;
  text-transform: none;
}

.ellia-beauty-settings-options {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  width: 100%;
}

.ellia-beauty-settings-option {
  position: relative;
  z-index: 20;
  flex: 1 1 auto;
  padding: 0.6rem 0.5rem;
  border: none;
  border-bottom: 1px solid rgba(224, 176, 255, 0.05);
  background: transparent;
  color: rgba(240, 220, 252, 0.5);
  font-family: inherit;
  font-size: 0.85rem;
  letter-spacing: 0.05em;
  text-align: center;
  cursor: pointer;
  transition: all 0.3s ease;
}

.ellia-beauty-settings-option:hover {
  border-bottom-color: rgba(224, 176, 255, 0.3);
  color: #fff;
  text-shadow: 0 0 10px rgba(224, 176, 255, 0.8);
}

.ellia-beauty-settings-option.is-active {
  border-bottom: 1px solid rgba(202, 164, 93, 0.5);
  background: radial-gradient(ellipse at bottom, rgba(202, 164, 93, 0.15) 0%, transparent 60%);
  color: #caa45d;
  text-shadow: 0 0 15px rgba(202, 164, 93, 0.6);
}

.ellia-beauty-settings-option.is-active::before {
  content: '✦ ';
  margin-right: 4px;
  font-size: 0.7rem;
}

.ellia-beauty-settings-option.is-active::after {
  content: ' ✦';
  margin-left: 4px;
  font-size: 0.7rem;
}

.ellia-beauty-planchette-wrapper {
  position: relative;
  z-index: 20;
  width: 160px;
  height: 200px;
  margin-bottom: 1.5rem;
  animation: ellia-beauty-mystic-float 6s ease-in-out infinite;
}

.ellia-beauty-svg-planchette {
  width: 100%;
  height: 100%;
  filter: drop-shadow(0 5px 10px rgba(0, 0, 0, 0.8));
}

.ellia-beauty-detail-title {
  margin-bottom: 0.2rem;
  color: #caa45d;
  font-size: 1.2rem;
  letter-spacing: 0.2em;
  text-align: center;
  text-shadow: 0 0 12px rgba(202, 164, 93, 0.4);
}

.ellia-beauty-detail-subtitle {
  margin-bottom: 2rem;
  color: rgba(224, 176, 255, 0.5);
  font-size: 0.65rem;
  letter-spacing: 0.4em;
  text-transform: uppercase;
}

.ellia-beauty-flavor-text {
  margin-top: 1rem;
  color: #e0b0ff;
  font-size: 0.9rem;
  line-height: 1.6;
  letter-spacing: 0.1em;
  text-align: center;
  text-shadow: 0 0 8px rgba(155, 89, 182, 0.6);
}

.ellia-beauty-flavor-text span,
.ellia-beauty-ticket-detail-status span {
  color: rgba(224, 176, 255, 0.4);
  font-size: 0.75rem;
}

.ellia-beauty-ticket-detail-status {
  width: 90%;
  margin-top: 1.5rem;
  padding-top: 1rem;
  border-top: 1px solid rgba(202, 164, 93, 0.3);
  color: #f1dcff;
  font-size: 0.75rem;
  line-height: 1.8;
  text-align: center;
}

.ellia-beauty-pane-right-intro {
  align-items: center;
  justify-content: center;
}

.ellia-beauty-intro-greeting {
  position: relative;
  margin-bottom: 2rem;
  color: #e0b0ff;
  font-size: 0.95rem;
  line-height: 1.8;
  letter-spacing: 0.05em;
  text-align: justify;
  text-shadow: 0 0 8px rgba(0, 0, 0, 0.8);
}

.ellia-beauty-intro-greeting span {
  color: #caa45d;
  opacity: 0.9;
}

.ellia-beauty-section-title {
  display: flex;
  align-items: center;
  margin-bottom: 1.2rem;
  color: #caa45d;
  font-size: 0.9rem;
  letter-spacing: 0.2em;
  text-shadow: 0 0 10px rgba(202, 164, 93, 0.4);
}

.ellia-beauty-section-title svg {
  width: 14px;
  height: 14px;
  margin-right: 8px;
  fill: none;
  stroke: #caa45d;
  stroke-width: 1.5;
}

.ellia-beauty-mechanic-item {
  margin-bottom: 1.5rem;
}

.ellia-beauty-mechanic-title {
  display: flex;
  align-items: center;
  margin-bottom: 0.4rem;
  color: #f1dcff;
  font-size: 0.95rem;
  font-weight: 600;
  text-shadow: 0 0 5px rgba(155, 89, 182, 0.5);
}

.ellia-beauty-mechanic-title::before {
  content: '✦';
  margin-right: 6px;
  color: #caa45d;
  font-size: 0.7rem;
}

.ellia-beauty-mechanic-desc {
  padding-left: 1.2rem;
  color: rgba(220, 200, 255, 0.7);
  font-size: 0.85rem;
  line-height: 1.8;
  text-align: justify;
}

.ellia-beauty-portrait-wrapper {
  position: relative;
  width: clamp(260px, 34vw, 360px);
  height: clamp(260px, 34vw, 360px);
  margin-bottom: 1.5rem;
  border-radius: 50%;
  overflow: hidden;
  box-shadow: 0 0 30px rgba(0, 0, 0, 0.8);
  animation: ellia-beauty-mystic-float 6s ease-in-out infinite;
}

.ellia-beauty-portrait {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
  transition: transform 0.5s ease;
}

.ellia-beauty-portrait-wrapper:hover .ellia-beauty-portrait {
  transform: scale(1.05);
}

.ellia-beauty-portrait-frame {
  position: absolute;
  inset: 0;
  border: 2px solid rgba(202, 164, 93, 0.4);
  border-radius: 50%;
  box-shadow: inset 0 0 20px rgba(202, 164, 93, 0.2);
  pointer-events: none;
}

.ellia-beauty-portrait-frame::after {
  content: '';
  position: absolute;
  inset: -2px;
  border: 1px dashed rgba(202, 164, 93, 0.6);
  border-radius: 50%;
  animation: ellia-beauty-spin 30s linear infinite;
}

@keyframes ellia-beauty-spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

.ellia-beauty-lore-footer {
  margin-top: auto;
  padding-top: 1.2rem;
  border-top: 1px dashed rgba(202, 164, 93, 0.2);
  color: rgba(202, 164, 93, 0.6);
  font-size: 0.75rem;
  line-height: 1.6;
  letter-spacing: 0.1em;
  text-align: center;
}

:global(.ellia-v2-root[data-animations-enabled='false'] .ellia-beauty-nav-btn),
:global(.ellia-v2-root[data-animations-enabled='false'] .ellia-beauty-settings-option) {
  transition: none !important;
}

:global(.ellia-v2-root[data-animations-enabled='false'] .ellia-beauty-planchette-wrapper) {
  animation: none !important;
}

@keyframes ellia-beauty-mystic-float {
  0% {
    filter: none;
    transform: translateY(0) rotate(0deg);
  }
  50% {
    filter: drop-shadow(0 10px 15px rgba(202, 164, 93, 0.2));
    transform: translateY(-10px) rotate(2deg);
  }
  100% {
    filter: none;
    transform: translateY(0) rotate(0deg);
  }
}

@media (max-width: 900px) {
  .ellia-beauty-shell {
    flex-direction: column;
    gap: 1.5rem;
    min-height: auto;
    padding: 3.2rem 1.4rem 1.4rem;
  }

  .ellia-beauty-pane-left,
  .ellia-beauty-pane-right {
    flex: 1;
    padding: 0;
  }

  .ellia-beauty-pane-left::after {
    display: none;
  }
}

@media (max-width: 640px) {
  .ellia-beauty-shell {
    padding: 3rem 1rem 1rem;
  }

  .ellia-beauty-portrait-wrapper {
    width: min(78vw, 300px);
    height: min(78vw, 300px);
  }

  .ellia-beauty-nav-btn {
    font-size: 0.72rem;
  }

  .ellia-beauty-nav-btn-left {
    left: 1rem;
  }

  .ellia-beauty-nav-btn-right {
    right: 1rem;
  }
}
